function createSessionToken() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 10);
}

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function asObject(value) {
  return value && typeof value === 'object' && !Array.isArray(value) ? value : {};
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asInt(value, fallback = 0) {
  const num = Number(value);
  return Number.isFinite(num) ? Math.floor(num) : fallback;
}

function slugifyBookName(value) {
  const normalized = String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '');

  if (!normalized) {
    return 'book';
  }

  return normalized.slice(0, 80) || 'book';
}

function buildReadableContent(manifest) {
  const book = asObject(manifest.book);
  const video = asObject(manifest.video);
  const metadata = asObject(manifest.metadata);
  const scenes = asArray(manifest.scenes).sort((a, b) => asInt(a.order) - asInt(b.order));

  const lines = [];

  lines.push(`# ${safeText(book.title, 'Sach chua ro ten')}`);

  if (safeText(book.author)) {
    lines.push(`Tac gia: ${safeText(book.author)}`);
  }

  const styleKeywords = asArray(book.style_keywords).map((item) => safeText(item)).filter(Boolean);
  if (styleKeywords.length) {
    lines.push(`Style keywords: ${styleKeywords.join(', ')}`);
  }

  const aspectRatio = safeText(video.aspect_ratio, '16:9');
  const minSec = asInt(video.target_duration_min_sec);
  const maxSec = asInt(video.target_duration_max_sec);
  const estSec = asInt(video.estimated_total_duration_sec);

  lines.push(`Video: ${aspectRatio} | ${minSec}-${maxSec}s | est ${estSec}s`);

  lines.push('');
  lines.push('## Metadata');
  lines.push(`Title: ${safeText(metadata.title)}`);

  if (safeText(metadata.thumbnail_text)) {
    lines.push(`Thumbnail: ${safeText(metadata.thumbnail_text)}`);
  }

  if (safeText(metadata.caption)) {
    lines.push('');
    lines.push('Caption:');
    lines.push(normalizeText(metadata.caption));
  }

  const hashtags = asArray(metadata.hashtags).map((item) => safeText(item)).filter(Boolean);
  if (hashtags.length) {
    lines.push('');
    lines.push(`Hashtags: ${hashtags.join(' ')}`);
  }

  for (const scene of scenes) {
    const sceneId = safeText(scene.scene_id, 'scene');
    const sceneTitle = safeText(scene.scene_title, sceneId);
    const sceneRole = safeText(scene.scene_role, 'core');
    const duration = asInt(scene.estimated_duration_sec);
    const narration = normalizeText(scene.narration_text);
    const quote = safeText(scene.highlight_quote_vi);

    lines.push('');
    lines.push(`## ${sceneId} - ${sceneTitle}`);
    lines.push(`Role: ${sceneRole} | Order: ${asInt(scene.order)} | Duration: ${duration}s`);

    if (quote) {
      lines.push(`Highlight quote: "${quote}"`);
    }

    if (narration) {
      lines.push('');
      lines.push(narration);
    }
  }

  return lines.join('\n').replace(/\n{3,}/g, '\n\n').trim();
}

const manifestRaw = asObject($('Manifest AI Agent').first().json.output);
const qc = asObject($('QC AI Agent').first().json.output);

if (Object.keys(manifestRaw).length === 0) {
  throw new Error('Manifest output is missing from merged payload.');
}

if (Object.keys(qc).length === 0) {
  throw new Error('QC output is missing from merged payload.');
}

const bookRaw = asObject(manifestRaw.book);
const videoRaw = asObject(manifestRaw.video);
const metadataRaw = asObject(manifestRaw.metadata);

const manifest = {
  ...manifestRaw,
  book: {
    title: normalizeText(bookRaw.title),
    author: normalizeText(bookRaw.author),
    style_keywords: asArray(bookRaw.style_keywords).map((item) => safeText(item)).filter(Boolean),
  },
  video: {
    aspect_ratio: safeText(videoRaw.aspect_ratio, '16:9'),
    target_duration_min_sec: asInt(videoRaw.target_duration_min_sec, 900),
    target_duration_max_sec: asInt(videoRaw.target_duration_max_sec, 1200),
    estimated_total_duration_sec: asInt(videoRaw.estimated_total_duration_sec, 0),
  },
  metadata: {
    ...metadataRaw,
    title: normalizeText(metadataRaw.title),
    caption: normalizeText(metadataRaw.caption),
    thumbnail_text: normalizeText(metadataRaw.thumbnail_text),
    hashtags: asArray(metadataRaw.hashtags).map((item) => safeText(item)).filter(Boolean),
  },
  scenes: asArray(manifestRaw.scenes)
    .map((scene, index) => {
      const s = asObject(scene);
      return {
        ...s,
        scene_id: safeText(s.scene_id, 'scene_' + String(index + 1).padStart(2, '0')),
        order: asInt(s.order, index + 1),
        scene_title: normalizeText(s.scene_title),
        scene_role: safeText(s.scene_role, index === 0 ? 'hook' : 'core'),
        narration_text: normalizeText(s.narration_text),
        image_prompt_en: normalizeText(s.image_prompt_en),
        highlight_quote_vi: normalizeText(s.highlight_quote_vi),
        estimated_duration_sec: asInt(s.estimated_duration_sec, 0),
        transition: safeText(s.transition, 'cut'),
      };
    })
    .sort((a, b) => a.order - b.order),
};

const contentReadable = buildReadableContent(manifest);

const sessionToken = safeText(createSessionToken(), 'session');
const safeToken = sessionToken.replace(/[^a-zA-Z0-9_-]+/g, '-').replace(/^-+|-+$/g, '') || 'session';

const safeBookName = slugifyBookName(
  safeText(`${manifest.book.title}-${manifest.book.author}`, 'book')
);

return {
  manifest,
  manifestJSONString: JSON.stringify(manifest, null, 2),
  contentReadable,
  qc,
  ggDriveFolderName: `${safeBookName}-${safeToken}`,
};

